targets.expr:
count(
  (longhorn_backup_state{recurring_job=~"$recurring_job"} == 4)
  and on(volume) longhorn_volume_last_backup_at{pvc!="",pvc_namespace=~"$namespace",pvc=~"$pvc",volume=~"$pv_name"}
) OR on() vector(0)

sum by (pvc_namespace, pvc, volume) (
  (longhorn_backup_actual_size_bytes
  * on(volume) group_left(pvc, pvc_namespace) (max by(volume, pvc, pvc_namespace)(longhorn_volume_capacity_bytes) > bool 0))
  and on(volume) longhorn_volume_last_backup_at{pvc!="",pvc_namespace=~"$namespace",pvc=~"$pvc",volume=~"$pv_name"}
)

(
  (longhorn_backup_state{recurring_job=~"$recurring_job"} >= 4)
  * on(volume) group_left(pvc, pvc_namespace) (max by(volume, pvc, pvc_namespace)(longhorn_volume_capacity_bytes) > bool 0)
)
and on(volume) longhorn_volume_last_backup_at{pvc!="",pvc_namespace=~"$namespace",pvc=~"$pvc"}

sum by (pvc_namespace, pvc) (
  (longhorn_backup_actual_size_bytes{recurring_job=~"$recurring_job"}
  * on(volume) group_left(pvc, pvc_namespace) (max by(volume, pvc, pvc_namespace)(longhorn_volume_capacity_bytes) > bool 0))
  and on(volume) longhorn_volume_last_backup_at{pvc!="",pvc_namespace=~"$namespace",pvc=~"$pvc"}
)
